    pub fn handle_trade(&self, mut client: Value, mut message: Value) {
        //
        //     {
        //         "e": "aggTrade",
        //         "E": 1754551358681,
        //         "a": 20505890,
        //         "s": "BTCUSDT",
        //         "p": "114783.7",
        //         "q": "0.020",
        //         "f": 26024678,
        //         "l": 26024682,
        //         "T": 1754551358528,
        //         "m": false
        //     }
        //
        let mut marketType: Value = self.get_account_type_from_url(get_value(&client, &Value::Str("url".to_string())));
        let mut trade: Value = message.clone();
        let mut marketId: Value = self.safe_string_k(trade.clone(), "s", &[]);
        let mut market: Value = self.safe_market(&[marketId.clone(), Value::Null, Value::Null, marketType.clone()]);
        let mut parsed: Value = self.parse_ws_trade(trade.clone(), &[market.clone()]);
        let mut symbol: Value = get_value(&parsed, &Value::Str("symbol".to_string()));
        if is_equal(&symbol, &Value::Null) {
            return;
        }
        if !is_true(&(Value::Bool(in_op(&self.trades, &symbol)))) {
            let mut limit: Value = self.safe_integer_k(self.options.clone(), "tradesLimit", &[Value::Int(1000)]);
            add_element_to_object(&mut self.trades.clone(), &symbol, ArrayCache::new(limit.clone()));
        }
        let mut stored: Value = get_value(&self.trades, &symbol);
        stored.append(parsed.clone());
        client.resolve(&[stored.clone(), add(&Value::Str("trade::".to_string()), &symbol)]);
}

